{"query":"

	fragment FragmentItemsFields on ItemDto {
		colorId
		customized
		itemId
		look
		price {
			current {
				currentPrice: amount
			}
			initial {
				initialPrice: amount
			}
		}
		productId
		quantity
		seller
		sizeId
		outOfStock
	}


	fragment FragmentSummaryFields on SummaryDto {
		deliveryCost {
			deliveryAmount: amount
		}
		freeShipping
		promoteShippingToStore
		subtotal {
			subTotalPrice: amount
		}
		total {
			totalPrice: amount
		}
		remainingCostToBeFreeShipping {
			untilFree: amount
		}
		taxable
		saved {
			amount
		}
		original {
			amount
		}
	}

	mutation AddItem(
		$channel: String!
		$item: ShoppingCartAddItemInput!
		$orderBy: ShoppingCartOrderByInput
	) {
		addItem(channel: $channel, item: $item, orderBy: $orderBy) {
			items {
				...FragmentItemsFields
			}
			summary {
				...FragmentSummaryFields
			}
			totalItems
			metadata {
				limitsExceeded
			}
		}
	}
","variables":{"orderBy":{"createdAt":"DESC"},"channel":"shop","item":{"colorId":"31","productId":"67057913","seller":"mango","sizeId":"40","look":"00"}}}

